// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for managed stock data (initialized from props, updated by stream)
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());

  // Update stocks when prop changes
  useEffect(() => {
    if (props.stocks) {
      setStocks(props.stocks);
    }
  }, [props.stocks]);

  // Merge price updates from stream into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const updatedStocks = stocks.map((stock) => {
        if (stock.symbol === priceUpdate.latest?.symbol) {
          return {
            ...stock,
            price: priceUpdate.latest.price ?? stock.price,
            change: priceUpdate.latest.change ?? stock.change,
            changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
          };
        }
        return stock;
      });
      setStocks(updatedStocks);
      setLastUpdated(new Date());

      // Trigger flash animation for updated symbol
      if (priceUpdate.latest.symbol) {
        setFlashingSymbols((prev) => new Set(prev).add(priceUpdate.latest.symbol!));
        setTimeout(() => {
          setFlashingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(priceUpdate.latest.symbol!);
            return next;
          });
        }, 500);
      }
    }
  }, [priceUpdate.latest, stocks]);

  // Helper to format price with 2 decimals
  const formatPrice = (price?: number): string => {
    if (price === undefined) return '—';
    return `$${price.toFixed(2)}`;
  };

  // Helper to format change percentage
  const formatChangePercent = (changePercent?: number): string => {
    if (changePercent === undefined) return '—';
    const sign = changePercent > 0 ? '+' : '';
    return `${sign}${changePercent.toFixed(2)}%`;
  };

  // Helper to determine color based on change
  const getChangeColor = (change?: number): string => {
    if (change === undefined) return 'var(--ggui-color-onSurface)';
    return change >= 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Helper to get arrow icon
  const getArrowIcon = (change?: number): string => {
    if (change === undefined) return '—';
    return change >= 0 ? '▲' : '▼';
  };

  return (
    <Container maxWidth='2xl' padding='var(--ggui-spacing-6)' center>
      {/* Header with title and last updated */}
      <Stack gap='var(--ggui-spacing-6)'>
        <Row align='center' justify='between'>
          <Heading level={1} color='var(--ggui-color-onSurface)'>
            Market Watch
          </Heading>
          <Stack direction='horizontal' align='center' gap='var(--ggui-spacing-2)'>
            <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant)'>
              Last Updated:
            </Text>
            <Text variant='bodySmall' color='var(--ggui-color-onSurface)' weight='semibold'>
              {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </Text>
          </Stack>
        </Row>

        {/* Responsive grid of stock cards */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
            '@media (max-width: 768px)': {
              gridTemplateColumns: '1fr',
            },
          } as React.CSSProperties}
        >
          {stocks.length > 0 ? (
            stocks.map((stock) => {
              const isFlashing = flashingSymbols.has(stock.symbol || '');
              const changeColor = getChangeColor(stock.change);
              const isPositive = (stock.change ?? 0) >= 0;

              return (
                <Card
                  key={stock.symbol}
                  padding='var(--ggui-spacing-4)'
                  shadow='md'
                  radius='lg'
                  border={true}
                  style={{
                    borderColor: changeColor,
                    transition: isFlashing ? 'background-color 0.5s ease-out' : 'none',
                    backgroundColor: isFlashing
                      ? isPositive
                        ? 'var(--ggui-color-success-50)'
                        : 'var(--ggui-color-error-50)'
                      : 'var(--ggui-color-surface)',
                  } as React.CSSProperties}
                >
                  <Stack gap='var(--ggui-spacing-3)'>
                    {/* Ticker symbol - large and bold */}
                    <Text variant='overline' color='var(--ggui-color-onSurfaceVariant)' size='xs'>
                      {stock.symbol || '—'}
                    </Text>
                    <Heading level={3} color='var(--ggui-color-onSurface)'>
                      {stock.symbol || 'N/A'}
                    </Heading>

                    {/* Company name */}
                    <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant)'>
                      {stock.name || 'Unknown Company'}
                    </Text>

                    {/* Current price */}
                    <Text variant='body' color='var(--ggui-color-onSurface)' weight='semibold' size='lg'>
                      {formatPrice(stock.price)}
                    </Text>

                    {/* Divider */}
                    <Divider margin='var(--ggui-spacing-2)' />

                    {/* Change amount and percentage with arrow */}
                    <Row align='center' justify='between'>
                      <Stack direction='horizontal' align='center' gap='var(--ggui-spacing-1)'>
                        <Text variant='body' color={changeColor} weight='semibold'>
                          {stock.change !== undefined
                            ? (stock.change > 0 ? '+' : '') + stock.change.toFixed(2)
                            : '—'}
                        </Text>
                      </Stack>
                      <Stack direction='horizontal' align='center' gap='var(--ggui-spacing-1)'>
                        <Text variant='body' color={changeColor} weight='semibold'>
                          {formatChangePercent(stock.changePercent)}
                        </Text>
                        <Text variant='body' color={changeColor} size='lg'>
                          {getArrowIcon(stock.change)}
                        </Text>
                      </Stack>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Card padding='var(--ggui-spacing-6)' shadow='sm'>
              <Text variant='body' color='var(--ggui-color-onSurfaceVariant)' align='center'>
                No stock data available. Waiting for market data...
              </Text>
            </Card>
          )}
        </Box>
      </Stack>
    </Container>
  );
}
